+    pub consecutive_zero_scans: u64,
+    pub total_ingests: u64,
+    pub seconds_since_last_ingest: Option<u64>,
+    pub warning_emitted: bool,
+    pub config_action: String,
+    pub config_threshold_hours: u64,
+}
